// Función para parsear y escribir archivos desde código de agentes
async function parseAndWriteFiles(codigo, jobId) {
  if (!codigo || typeof codigo !== 'string') return;

  const pattern = /ARCHIVO:(.+?)\n([\s\S]+?)FIN_ARCHIVO/g;
  const matches = [...codigo.matchAll(pattern)];

  if (matches.length === 0) return;

  const timestamp = new Date().toISOString();
  console.log(`[${timestamp}] [Job ${jobId}] Detectados ${matches.length} archivo(s) para escribir`);

  for (const match of matches) {
    const filepath = match[1].trim();
    const contenido = match[2];

    // Validación: ruta debe comenzar con /home/agentes/
    if (!filepath.startsWith('/home/agentes/')) {
      const errorMsg = `Ruta inválida bloqueada: ${filepath} (debe comenzar con /home/agentes/)`;
      console.error(`[${timestamp}] [Job ${jobId}] ${errorMsg}`);
      continue;
    }

    try {
      // Crear directorio si no existe
      const dir = path.dirname(filepath);
      await fs.mkdir(dir, { recursive: true });

      // Escribir archivo
      await fs.writeFile(filepath, contenido, 'utf8');

      const successMsg = `Archivo escrito: ${filepath} (${contenido.length} bytes)`;
      console.log(`[${timestamp}] [Job ${jobId}] ✓ ${successMsg}`);

      // Actualizar log del job
      const job = jobs.get(jobId);
      if (job && job.log) {
        job.log.push(`[${timestamp}] ${successMsg}`);
      }

    } catch (error) {
      const errorMsg = `Error escribiendo ${filepath}: ${error.message}`;
      console.error(`[${timestamp}] [Job ${jobId}] ✗ ${errorMsg}`);

      // Registrar error en job
      const job = jobs.get(jobId);
      if (job && job.log) {
        job.log.push(`[${timestamp}] ERROR: ${errorMsg}`);
      }

      // Si es error de permisos, loguearlo específicamente
      if (error.code === 'EACCES') {
        console.error(`[${timestamp}] [Job ${jobId}] Permisos insuficientes para ${filepath}`);
      }
    }
  }
}

// Procesar subtarea con agente específico
async function procesarSubtarea(jobId, subtarea, indice) {
  const job = jobs.get(jobId);
  const timestamp = new Date().toISOString();

  job.log.push(`[${timestamp}] Iniciando subtarea ${indice + 1}: ${subtarea.descripcion}`);
  job.log.push(`[${timestamp}] Agente asignado: ${subtarea.agente}`);
  job.agenteActual = subtarea.agente;
  job.subtareas[indice].estado = 'EJECUTANDO';

  const agente = agents[subtarea.agente];
  if (!agente) {
    job.log.push(`[${timestamp}] ERROR: Agente ${subtarea.agente} no encontrado`);
    job.subtareas[indice].estado = 'ERROR';
    job.subtareas[indice].error = 'Agente no encontrado';
    return { exito: false, error: 'Agente no encontrado' };
  }

  try {
    const resultado = await agente.ejecutar(subtarea.prompt);

    // **INTEGRACIÓN: Parsear y escribir archivos después de ejecutar agente**
    if (resultado && resultado.codigo) {
      await parseAndWriteFiles(resultado.codigo, jobId);
    }

    job.subtareas[indice].resultado = resultado;
    job.subtareas[indice].estado = 'COMPLETADA';
    job.log.push(`[${timestamp}] Subtarea ${indice + 1} completada por ${subtarea.agente}`);

    return { exito: true, resultado };
  } catch (error) {
    job.log.push(`[${timestamp}] ERROR en subtarea ${indice + 1}: ${error.message}`);
    job.subtareas[indice].estado = 'ERROR';
    job.subtareas[indice].error = error.message;
    return { exito: false, error: error.message };
  }
}

