    fin: null,
    subtareas: [],
    log: [`[${timestamp}] Job ${jobId} creado para proyecto: ${proyecto}`],
    agenteActual: null
  };

  jobs.set(jobId, job);

  // Ejecutar de forma asíncrona
  (async () => {
    try {
      job.estado = 'PLANIFICANDO';
      job.agenteActual = 'planner';
      job.log.push(`[${new Date().toISOString()}] Solicitando plan a Planner...`);

      const plan = await agents.planner.ejecutar(descripcion, proyecto);

      if (!plan || !plan.subtareas || plan.subtareas.length === 0) {
        throw new Error('Plan inválido generado por Planner');
