      job.subtareas = plan.subtareas.map(st => ({
        ...st,
        estado: 'PENDIENTE',
        resultado: null,
        error: null
      }));

      job.log.push(`[${new Date().toISOString()}] Plan recibido: ${plan.subtareas.length} subtareas`);
      job.estado = 'EJECUTANDO';

      // Ejecutar subtareas secuencialmente
      for (let i = 0; i < job.subtareas.length; i++) {
        const resultado = await procesarSubtarea(jobId, job.subtareas[i], i);
        if (!resultado.exito) {
          job.estado = 'ERROR';
          job.fin = new Date().toISOString();
          job.log.push(`[${job.fin}] Job fallido en subtarea ${i + 1}`);
          return;
        }
      }

      job.estado = 'COMPLETADO';
      job.fin = new Date().toISOString();
      job.agenteActual = null;
      job.log.push(`[${job.fin}] Job completado exitosamente`);

    } catch (error) {
      job.estado = 'ERROR';
      job.fin = new Date().toISOString();
      job.agenteActual = null;
      job.log.push(`[${job.fin}] ERROR FATAL: ${error.message}`);
    }
  })();

  res.json({ jobId, estado: 'EN COLA', mensaje: 'Tarea encolada' });
});

