// Función de escritura segura
async function escribirArchivoSeguro(ruta, contenido, agente) {
  try {
    // 1. Normalizar ruta
    const rutaAbsoluta = path.resolve(ruta);
    const baseDir = path.resolve('/home/agentes');

    // 2. Validar seguridad
    if (!rutaAbsoluta.startsWith(baseDir)) {
      throw new Error(`Ruta fuera de zona segura: ${ruta}`);
    }

    if (rutaAbsoluta.includes('node_modules')) {
      throw new Error('No se puede escribir en node_modules');
    }

    // 3. Validar tamaño
    const tamaño = Buffer.byteLength(contenido, 'utf8');
    if (tamaño > 5 * 1024 * 1024) { // 5MB
      throw new Error(`Archivo muy grande: ${tamaño} bytes`);
    }

    // 4. Crear directorio si no existe
    const dir = path.dirname(rutaAbsoluta);
    await fs.mkdir(dir, { recursive: true });

    // 5. Escribir archivo
    await fs.writeFile(rutaAbsoluta, contenido, 'utf8');

    // 6. Log éxito
    console.log(`[WRITE OK] ${agente} → ${ruta} (${tamaño} bytes)`);

    return { success: true, ruta, tamaño };

  } catch (error) {
    console.error(`[WRITE ERROR] ${agente} → ${ruta}: ${error.message}`);
    return { success: false, error: error.message };
  }
}

